	// In OpenMP, we can parallelize the outer loop over `i` (diagonals).
	// For each diagonal `i`, we need to launch `i` "blocks" (simulated by threads).
	for( int i = 1 ; block_width >= i ; i++){
		// For each diagonal `i`, we launch `i` blocks.
		// We use `#pragma omp parallel for` to parallelize the execution of these `i` blocks.
		// Each thread in the team will execute the `needle_kernel_1` function.
		// The number of threads in the team should be at least `i`.
		// `schedule(static)` is used for simplicity, though dynamic scheduling might be better for load balancing.
		#pragma omp parallel for schedule(static) num_threads(i)
		for(int block_idx = 0; block_idx < i; ++block_idx) {
			// Call the adapted kernel function.
			// `block_idx` here corresponds to `bx` in the kernel, which is `blockIdx.x` in CUDA.
			// The `i` from the outer loop is passed as `diag_idx`.
			needle_kernel_1(referrence_cuda, matrix_cuda, max_cols, penalty, i, block_width);
		}
